import{_ as e,o,c as l,a6 as n}from"./chunks/framework.wLlb4ebq.js";const p=JSON.parse('{"title":"UI 手工回归清单（Linux.do / Notion / 通用网页 / chrome-extension-full）","description":"","frontmatter":{},"headers":[],"relativePath":"ui-regression-checklist.md","filePath":"ui-regression-checklist.md"}'),t={name:"ui-regression-checklist.md"};function a(r,i,c,s,d,u){return o(),l("div",null,[...i[0]||(i[0]=[n('<h1 id="ui-手工回归清单-linux-do-notion-通用网页-chrome-extension-full" tabindex="-1">UI 手工回归清单（Linux.do / Notion / 通用网页 / chrome-extension-full） <a class="header-anchor" href="#ui-手工回归清单-linux-do-notion-通用网页-chrome-extension-full" aria-label="Permalink to “UI 手工回归清单（Linux.do / Notion / 通用网页 / chrome-extension-full）”">​</a></h1><blockquote><p>适用脚本：<code>LinuxDo-Bookmarks-to-Notion.user.js</code></p><p>建议每次 UI 大改后先跑自动化基线：<code>npm run verify:baseline</code>。如涉及扩展形态，再补 <code>npm run verify:extension:bounded</code> 与 <code>npm run build:extension</code>，然后按本清单做手工回归。</p></blockquote><h2 id="_0-通用检查-所有站点" tabindex="-1">0. 通用检查（所有站点） <a class="header-anchor" href="#_0-通用检查-所有站点" aria-label="Permalink to “0. 通用检查（所有站点）”">​</a></h2><ul><li>[ ] 页面刷新后 UI 样式不重复注入（无明显样式叠加/抖动/字体异常）</li><li>[ ] 按钮/输入/选择器在 <code>Tab</code> 导航下有清晰焦点环（<code>:focus-visible</code>）</li><li>[ ] 系统开启“减少动态效果”（<code>prefers-reduced-motion</code>）时，无明显闪烁/强动画</li></ul><h2 id="_1-linux-do-收藏页-ui-面板" tabindex="-1">1. Linux.do（收藏页 UI 面板） <a class="header-anchor" href="#_1-linux-do-收藏页-ui-面板" aria-label="Permalink to “1. Linux.do（收藏页 UI 面板）”">​</a></h2><p>打开：<code>https://linux.do/u/&lt;你的用户名&gt;/activity/bookmarks</code></p><ul><li>[ ] 面板出现、标题栏可拖拽移动；缩放手柄可用（左边/下边/左下角）</li><li>[ ] “加载收藏列表”可用，计数更新，列表渲染正常</li><li>[ ] 勾选/全选/取消全选正常，已选数量显示正确</li><li>[ ] 导出流程按钮状态正确（开始/暂停/继续/取消），进度条与状态提示显示正常</li><li>[ ] AI 对话区可发送、可清空；设置折叠可打开/关闭；输入框回车发送正常</li><li>[ ] 日志面板可展开/收起，条目渲染正常；“清除日志”生效</li></ul><h2 id="_2-notion-浮动-ai-面板" tabindex="-1">2. Notion（浮动 AI 面板） <a class="header-anchor" href="#_2-notion-浮动-ai-面板" aria-label="Permalink to “2. Notion（浮动 AI 面板）”">​</a></h2><p>打开任意页面：<code>https://www.notion.so/</code></p><ul><li>[ ] 右下角浮动按钮出现；可拖拽；点击可开合面板</li><li>[ ] 面板可拉伸（左边/上边/左上角），关闭/展开逻辑正常</li><li>[ ] 对话区可发送；快捷 chips 点击可触发发送</li><li>[ ] “设置”折叠区可开合；保存设置后刷新仍能加载配置</li><li>[ ] 状态提示（info/success/error）显示与关闭按钮正常</li></ul><h2 id="_3-通用网页-剪藏导出面板" tabindex="-1">3. 通用网页（剪藏导出面板） <a class="header-anchor" href="#_3-通用网页-剪藏导出面板" aria-label="Permalink to “3. 通用网页（剪藏导出面板）”">​</a></h2><p>打开任意非 Linux.do/Notion 页面（例如新闻/博客/文档页）</p><ul><li>[ ] 右下角剪藏按钮出现；点击可打开/关闭面板</li><li>[ ] 面板预览区域显示标题/来源等元信息</li><li>[ ] 设置 API Key 的流程正常（Key 不预填到 DOM）</li><li>[ ] 导出按钮可触发导出；exporting/success/error 三种状态视觉可区分且可读</li><li>[ ] 面板可拉伸（左边/上边/左上角），不会遮挡主要操作按钮</li></ul><h2 id="_4-chrome-extension-full-独立扩展形态" tabindex="-1">4. <code>chrome-extension-full</code>（独立扩展形态） <a class="header-anchor" href="#_4-chrome-extension-full-独立扩展形态" aria-label="Permalink to “4. chrome-extension-full（独立扩展形态）”">​</a></h2><p>准备：</p><ul><li>[ ] 先执行 <code>node scripts/build-extension.js</code></li><li>[ ] 在 <code>chrome://extensions/</code> 中以“加载已解压的扩展程序”方式加载 <code>chrome-extension-full/</code></li></ul><p>检查：</p><ul><li>[ ] 扩展 Popup 可以正常打开，不出现空白页或脚本报错</li><li>[ ] Popup 中的快捷入口文案与当前稳定能力一致，不宣传内部或不稳定能力</li><li>[ ] 点击 Popup 中的来源/导入入口后，能把当前页面引导到对应宿主面或触发对应消息桥接</li><li>[ ] 在 Linux.do / Notion / GitHub / Zhihu / 任意通用网页上，content script 注入后不会出现明显的重复 UI、缺失样式或初始化失败</li><li>[ ] GitHub 页面能进入完整面板；Zhihu 与任意通用网页能出现右下角剪藏入口</li><li>[ ] 重新执行 <code>node scripts/build-extension.js</code> 后，扩展目录结构仍可被浏览器正常加载</li></ul>',18)])])}const x=e(t,[["render",a]]);export{p as __pageData,x as default};
